from flask import Flask, request

app = Flask(__name__)

@app.route('/')
def index():
    username = request.args.get('username')
    if not username:
        return "Please provide your name as a query parameter", 200

    welcome_message = f"**Hello**, _{username}_! Welcome to our website."
    return welcome_message, 200

if __name__ == "__main__":
    app.run(debug=True)